	public void UpdateResults(OverwatchLocation? location, bool showDead, bool showHidden, List<OverwatchMarine> marines, OverwatchConsoleComponent console)
	{
		//IL_010f: Unknown result type (might be due to invalid IL or missing references)
		string text = SearchBar.Text;
		if (string.IsNullOrWhiteSpace(text) && !location.HasValue && showDead && showHidden)
		{
			MakeAllVisible();
			ApplySquadInfoVisibilityState();
			return;
		}
		for (int i = 0; i < ((Control)Names).ChildCount; i++)
		{
			Control child = ((Control)Names).GetChild(i);
			Control child2 = ((Control)Roles).GetChild(i);
			if (!string.IsNullOrWhiteSpace(text) && !child.ChildrenContainText(text) && !child2.ChildrenContainText(text))
			{
				MakeViewVisible(i, visible: false);
				continue;
			}
			if (location.HasValue && (i >= marines.Count || marines[i].Location != location))
			{
				MakeViewVisible(i, visible: false);
				continue;
			}
			if (!showDead && (i >= marines.Count || marines[i].State != MobState.Alive))
			{
				MakeViewVisible(i, visible: false);
				continue;
			}
			if (!showHidden)
			{
				HashSet<NetEntity> hidden = console.Hidden;
				if (i >= marines.Count || hidden.Contains(marines[i].Id))
				{
					MakeViewVisible(i, visible: false);
					continue;
				}
			}
			MakeViewVisible(i, visible: true);
		}
		ApplySquadInfoVisibilityState();
	}

